[FormDataFieldEventHandler(formDataFieldStr(PurchAgreement, ALine, ItemId), FormDataFieldEventType::Modified)]
public static void ItemId_OnModified(FormDataObject sender, FormDataFieldEventArgs e)
{  
    FormDataSource        aline_ds  =  sender.datasource();
    AgreementLineQuantityCommitment         aline     =  aline_ds.cursor();
    ItemId                itemId    = sender.getValue();       
    InventTableModule     inventTableModule = InventTableModule::find(itemId,ModuleInventPurchSales::Purch);

    aline.ETG_OverDeliveryPct  = inventTableModule.OverDeliveryPct;
    aline.ETG_UnderDeliveryPct = inventTableModule.UnderDeliveryPct;
    aline.ETG_PriceType        = ETG_PriceType::Fixed;
    aline.DefaultDimension     = InventTable::find(itemId).DefaultDimension;
    aline.IsMaxEnforced        = NoYes::Yes;
    aline.CommitedQuantity     = 0;
    // NS, DLT , 04/03/2025 Item description  - should not show item number but actual product description
    aline.ETG_ItemAlternativeName = aline.name();
    // NE, DLT , 04/03/2025 Item description  - should not show item number but actual description
}

