/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(PurchAgreement, ALine), FormDataSourceEventType::Written)]
public static void ALine_OnWritten(FormDataSource sender, FormDataSourceEventArgs e)
{
    AgreementLineQuantityCommitment aline      =  sender.cursor();

    ETG_AgreementLineNotes       agreementlineNotes,agreementlineNotesDel;
    ETG_ItemQualityGrp           itemQualityGrp;
    ETG_ItemQualitySpecDetails   itemQualitySpecDetails;
    ETG_AgreementLineQualityGrp  agreementLineQualityGrp;
    ETGAgrrementQualitySpecsLine agreementQualitySpecsDetails;
    ETG_IsCreatedAgreement       isCreatedAgreement;

    ETGTradingNotes         tradingNotes;
    boolean                 isNotes = false;
    RecordInsertList        tmpInsNotes = new RecordInsertList(tableNum(ETG_AgreementLineNotes));
    RecordInsertList        tmpInsSpecGrp = new RecordInsertList(tableNum(ETG_AgreementLineQualityGrp));
    RecordInsertList        tmpInsSpecDetails = new RecordInsertList(tableNum(ETGAgrrementQualitySpecsLine));

    select firstonly isCreatedAgreement
        where isCreatedAgreement.AgreementLine == aline.RecId;

    if(!isCreatedAgreement)
    {
        isCreatedAgreement.clear();
        isCreatedAgreement.AgreementLine = aline.RecId;
        isCreatedAgreement.insert();

        while select EnumNotes,Description,PrintNotesInContract from tradingNotes
            where tradingNotes.ItemId == aline.ItemId
        {
            agreementlineNotes.AgreementLine = aline.RecId;
            agreementlineNotes.EnumNotes     = tradingNotes.EnumNotes;
            agreementlineNotes.Description   = tradingNotes.Description;
            agreementlineNotes.PrintNotesInContract = tradingNotes.PrintNotesInContract;
            agreementlineNotes.ItemId               = aline.ItemId;
            tmpInsNotes.add(agreementlineNotes);
        }

        while select * from itemQualityGrp
            where itemQualityGrp.ItemId  == aline.ItemId
        {
            agreementLineQualityGrp.GroupId         = itemQualityGrp.GroupId;
            agreementLineQualityGrp.AgreementLine   = aline.RecId;
            tmpInsSpecGrp.add(agreementLineQualityGrp);
        }

        while select * from itemQualitySpecDetails
            where itemQualitySpecDetails.ItemId == aline.ItemId
        {
            agreementQualitySpecsDetails.GroupID               = itemQualitySpecDetails.GroupID;
            agreementQualitySpecsDetails.MaxRange              = itemQualitySpecDetails.MaxRange;
            agreementQualitySpecsDetails.MinRange              = itemQualitySpecDetails.MinRange;
            agreementQualitySpecsDetails.AgreementLineRefrecid = aline.RecId;
            agreementQualitySpecsDetails.SubGrpId              = itemQualitySpecDetails.SubGrpId;
            agreementQualitySpecsDetails.SubGroupDescription   = itemQualitySpecDetails.SubGroupDescription;
            agreementQualitySpecsDetails.MeasurementType       = itemQualitySpecDetails.MeasurementType;
            agreementQualitySpecsDetails.AdjustmentType        = itemQualitySpecDetails.AdjustmentType;
            agreementQualitySpecsDetails.Increment             = itemQualitySpecDetails.Increment;
            agreementQualitySpecsDetails.FixedValue            = itemQualitySpecDetails.FixedValue;
            tmpInsSpecDetails.add(agreementQualitySpecsDetails);
        }

        tmpInsNotes.insertDatabase();
        tmpInsSpecGrp.insertDatabase();
        tmpInsSpecDetails.insertDatabase();
    }
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(PurchAgreement, ALine), FormDataSourceEventType::ValidatedWrite)]
public static void ALine_OnValidatedWrite(FormDataSource sender, FormDataSourceEventArgs e)
{
    AgreementLineQuantityCommitment aline      =  sender.cursor();

    if(aline.ETG_PriceType == ETG_PriceType::Fixed && !aline.PricePerUnit)
        throw Error('Unit price should be mandatory for fixed price type');

    if(aline.CommitedQuantity == 0)
        throw Error('Quantity must be filled in');
}
